import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import EditPurchase from './EditPurchase';
import './PurchaseFunc.css';
import AddPurchase from './AddPurchase';

const PurchaseFunc = () => {
  const [purchases, setPurchases] = useState([]);
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [locations, setLocations] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [isLoading, setIsLoading] = useState(true); // New state to track loading status

  const fetchData = useCallback(async () => {
    try {
      const [purchaseResponse, locationResponse, materialResponse, vendorResponse] = await Promise.all([
        fetch('http://localhost:8081/PurchasesAPI').then((response) => response.json()),
        fetch('http://localhost:8081/LocationsAPI').then((response) => response.json()),
        fetch('http://localhost:8081/materiallist').then((response) => response.json()),
        fetch('http://localhost:8081/vendors').then((response) => response.json()),
      ]);
  
      // Combine data after fetching all the required data
      const combinedData = purchaseResponse.map((purchase) => {
        const location = locationResponse.find((loc) => loc.id === purchase.location);
        const material = materialResponse.find((mat) => mat.matid === purchase.materialid);
        const vendor = vendorResponse.find((ven) => ven.vendorid === purchase.vendor);
        return {
          ...purchase,
          location: location ? location.locationname : 'Unknown Location',
          name: material ? material.name : 'Unknown Material',
          vendor: vendor ? vendor.name: 'Unknown Vendor',
        };
      });
  
      setPurchases(combinedData);
      setLocations(locationResponse);
      setMaterials(materialResponse);
      setVendors(vendorResponse);
      setIsLoading(false);
    } catch (error) {
      console.log('Error fetching data:', error);
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAdd = useCallback((newPurchase) => {
    
    // Make a POST request to add the new purchase
    fetch('http://localhost:8081/PurchasesAPI', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newPurchase),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding purchase');
        }
      })
      .then(() => {
        fetchData();
      })
      .catch((error) => {
        console.log('Error adding purchase:', error);
      });
  }, [fetchData]);

  const handleDelete = useCallback((deletedPurchase) => {
    const isConfirmed = window.confirm('Are you sure you want to delete this purchase?');
  
    if (isConfirmed) {
      fetch(`http://localhost:8081/PurchasesAPI/${deletedPurchase.id}`, {
        method: 'DELETE',
      })
        .then(() => {
          const updatedPurchaseList = purchases.filter((p) => p.id !== deletedPurchase.id);
          setPurchases(updatedPurchaseList);
        })
        .catch((error) => {
          console.log('Error deleting purchase:', error);
        });
    }
  }, [purchases]);

  const handleEdit = useCallback((purchase) => {
    if (editingPurchase && editingPurchase.id === purchase.id) {
      alert('Purchase is already being edited.');
      return;
    }

    setEditingPurchase(purchase);
  }, [editingPurchase]);

  const handleUpdate = useCallback(async (updatedPurchase) => {
    try {
      // Get the locationID from the location name
      const locationID = await getLocationIDFromName(updatedPurchase.location);
  
      // Update the purchase with the correct locationID
      const updatedPurchaseData = {
        ...updatedPurchase,
        location: locationID, // Use the locationID instead of the location name
      };
  
      // Make the PUT request to update the purchase
      const response = await fetch(`http://localhost:8081/PurchasesAPI/${updatedPurchase.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(updatedPurchaseData),
      });
  
      if (response.ok) {
        const data = await response.json();
        // Update the purchases state with the updated data
        const updatedPurchaseList = purchases.map((p) => (p.id === updatedPurchase.id ? data : p));
        setPurchases(updatedPurchaseList);
        setEditingPurchase(null);
      } else {
        throw new Error('Error updating the purchase');
      }
    } catch (error) {
      console.error('Error updating the purchase:', error);
      // Handle error or show an error message to the user
    }
  }, [purchases]);

  const getLocationIDFromName = async (locationName) => {
    try {
      const response = await fetch(`http://localhost:8081/locations/${locationName}`);
      const data = await response.json();
      if (data && data.locationID) {
        return data.locationID;
      } else {
        throw new Error('Location not found');
      }
    } catch (error) {
      console.error('Error fetching location ID:', error);
      throw error;
    }
  };
  
  
  const columns = React.useMemo(
    () => [
      { Header: 'ID', accessor: 'id' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'materialid' },
      { Header: 'Material Name', accessor: 'name' },
      { Header: 'Quantity', accessor: 'quantity' },      
      {
        Header: 'Vendor',
        accessor: 'vendor',
        Cell: ({ value }) => {
          // Instead of finding the vendor in the vendors array, directly use the value from the data
          return (
            <a href={`http://localhost:8081/vendors/${value}`} target="_blank" rel="noopener noreferrer">
              {value}
            </a>
          );
        },
      },
      { Header: 'Date', accessor: 'date' },
      { Header: 'Actions', accessor: 'actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete]
  );
  
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: purchases,locations,materials,
      initialState: {
        pageIndex: 0,
        pageSize: 10,
      },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  console.log('Purchases:', purchases);
  console.log('Locations:', locations);
  console.log('Materials:', materials);
  console.log('Vendors:', vendors);


  if (isLoading) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <AddPurchase handleAdd={handleAdd} />
      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="purchase-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingPurchase && editingPurchase.id === row.original.id && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditPurchase purchase={editingPurchase} handleUpdate={handleUpdate} />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(purchases.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

export default PurchaseFunc;
